const body = $json.body || $json;
const event = body.event || body;
const data = event.data || event;

const typeId = data.custom_activity_type_id || data._type || '';
const leadId = data.lead_id || '';
const userId = data.user_id || '';
const dateCreated = data.date_created || new Date().toISOString();

const typeMap = {
  'actitype_6GTMexlVYwCl3ER9rYB4x4': 'coldcalling',
  'actitype_4jcmhCre676aqKjDVWqODu': 'coldcalling',
  'actitype_0Pow7dFbqAOrFjLsCT068D': 'erstgespraech',
  'actitype_1t4dAEI4JjnbDr6mRnECr0': 'strategiegespraech'
};

const callType = typeMap[typeId] || null;
if (!callType) return [];

const date = new Date(dateCreated);
const dayStart = new Date(date.getFullYear(), date.getMonth(), date.getDate()).toISOString();
const dayEnd = new Date(date.getFullYear(), date.getMonth(), date.getDate() + 1).toISOString();

return [{ json: { callType, leadId, userId, dateCreated, dayStart, dayEnd, typeId } }];

const response = $('GET Close.io Calls').first().json;
const callsData = response.data || [];
const meta = $('Identify Activity Type').first().json;
const callType = meta.callType;
const leadId = meta.leadId;

const existing = await this.helpers.httpRequest({
  method: 'GET',
  url: $env.SUPABASE_LEADS_URL + '/rest/v1/transcripts?select=url&source_type=eq.call',
  headers: {
    'apikey': $env.SUPABASE_LEADS_KEY,
    'Authorization': 'Bearer ' + $env.SUPABASE_LEADS_KEY
  }
});
const transcribedUrls = new Set(
  (Array.isArray(existing) ? existing : []).filter(t => t && t.url).map(t => t.url)
);

let calls = callsData.filter(c => {
  if (!c.recording_url) return false;
  if (transcribedUrls.has(c.recording_url)) return false;
  if (callType === 'coldcalling' && c.direction !== 'outbound') return false;
  return true;
});

if (calls.length === 0) {
  return [{ json: { transcripts: [], notes: [], count: 0 } }];
}

function uuid() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
  });
}

const transcripts = [];
const notes = [];

for (let i = 0; i < calls.length; i++) {
  const call = calls[i];
  if (i > 0) await new Promise(r => setTimeout(r, 2000));

  try {
    const audioBuffer = await this.helpers.httpRequest({
      method: 'GET',
      url: call.recording_url,
      headers: {
        'Authorization': 'Basic YXBpXzJKd0JqaHMwYmZCUmJ5d3dHeXA0blUuMWlWV0NZVUUyRzE3NWh6NjJmNEJMRzo='
      },
      encoding: 'arraybuffer'
    });

    const boundary = '----n8nBoundary' + Date.now() + i;
    const modelPart = '--' + boundary + '\r\nContent-Disposition: form-data; name="model"\r\n\r\nwhisper-1\r\n';
    const fileHeader = '--' + boundary + '\r\nContent-Disposition: form-data; name="file"; filename="recording.mp3"\r\nContent-Type: audio/mpeg\r\n\r\n';
    const footer = '\r\n--' + boundary + '--\r\n';

    const bodyBuffer = Buffer.concat([
      Buffer.from(modelPart),
      Buffer.from(fileHeader),
      Buffer.from(audioBuffer),
      Buffer.from(footer)
    ]);

    const whisperResult = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.openai.com/v1/audio/transcriptions',
      headers: {
        'Authorization': 'Bearer ' + $env.OPENAI_API_KEY,
        'Content-Type': 'multipart/form-data; boundary=' + boundary
      },
      body: bodyBuffer
    });

    const transcriptText = typeof whisperResult === 'string' ? whisperResult : (whisperResult.text || JSON.stringify(whisperResult));

    const aiResult = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.openai.com/v1/chat/completions',
      headers: {
        'Authorization': 'Bearer ' + $env.OPENAI_API_KEY,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        model: 'gpt-4o',
        messages: [
          { role: 'system', content: 'Fasse das folgende Gespraechstranskript kurz und strukturiert zusammen. Gib die wichtigsten Punkte, Ergebnisse und naechste Schritte an. Antworte auf Deutsch.' },
          { role: 'user', content: transcriptText }
        ]
      })
    });

    const aiParsed = typeof aiResult === 'string' ? JSON.parse(aiResult) : aiResult;
    const summary = aiParsed.choices?.[0]?.message?.content || '';

    let sourceId;
    try {
      const callLookup = await this.helpers.httpRequest({
        method: 'GET',
        url: $env.SUPABASE_LEADS_URL + '/rest/v1/calls?select=id&close_call_id=eq.' + call.id + '&limit=1',
        headers: {
          'apikey': $env.SUPABASE_LEADS_KEY,
          'Authorization': 'Bearer ' + $env.SUPABASE_LEADS_KEY
        }
      });
      sourceId = Array.isArray(callLookup) && callLookup.length > 0 ? callLookup[0].id : uuid();
    } catch (e) {
      sourceId = uuid();
    }

    transcripts.push({
      source_type: 'call',
      source_id: sourceId,
      content: transcriptText,
      call_type: callType,
      summary: summary,
      url: call.recording_url,
      synced_at: new Date().toISOString()
    });

    const label = callType === 'erstgespraech' ? 'Erstgespraech' : 'Coldcalling';
    notes.push({
      lead_id: leadId,
      note: label + ' - Zusammenfassung\n\n' + summary + '\n\n---\nDatum: ' + (call.date_created || meta.dateCreated)
    });
  } catch (e) {
    continue;
  }
}

return [{ json: { transcripts, notes, count: transcripts.length } }];

const notes = $('Process Calls').first().json.notes;
for (let i = 0; i < notes.length; i++) {
  if (i > 0) await new Promise(r => setTimeout(r, 1000));
  await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.close.com/api/v1/activity/note/',
    headers: {
      'Authorization': 'Basic YXBpXzJKd0JqaHMwYmZCUmJ5d3dHeXA0blUuMWlWV0NZVUUyRzE3NWh6NjJmNEJMRzo=',
      'Content-Type': 'application/json'
    },
    body: JSON.stringify(notes[i])
  });
}
return [{ json: { notesPosted: notes.length } }];

const meta = $('Identify Activity Type').first().json;
const leadId = meta.leadId;
const dateCreated = meta.dateCreated;

const leads = await this.helpers.httpRequest({
  method: 'GET',
  url: $env.SUPABASE_LEADS_URL + '/rest/v1/leads?select=lead_name&close_lead_id=eq.' + leadId + '&limit=1',
  headers: {
    'apikey': $env.SUPABASE_LEADS_KEY,
    'Authorization': 'Bearer ' + $env.SUPABASE_LEADS_KEY
  }
});

if (!Array.isArray(leads) || leads.length === 0) {
  return [{ json: { transcript: null, note: null, count: 0 } }];
}

const leadName = leads[0].lead_name.toLowerCase();
const dayStr = new Date(dateCreated).toISOString().split('T')[0];

let allDemos = [];
let included = [];
let page = 1;
let hasMore = true;

while (hasMore) {
  try {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://demodesk.com/api/v1/demos?filter[schedule_eq]=past&filter[recordings_present]=true&page=' + page,
      headers: {
        'api-key': $env.DEMODESK_API_KEY,
        'Accept': 'application/json'
      }
    });
    const parsed = typeof resp === 'string' ? JSON.parse(resp) : resp;
    const demos = parsed.data || [];
    allDemos = allDemos.concat(demos);
    included = included.concat(parsed.included || []);
    hasMore = demos.length >= 25;
    page++;
  } catch (e) {
    hasMore = false;
  }
}

const recordingMap = {};
for (const item of included) {
  if (item.type === 'recordings' && item.attributes) {
    recordingMap[item.id] = item.attributes.token;
  }
}

let matchedToken = null;
for (const demo of allDemos) {
  const attrs = demo.attributes || {};
  const account = (attrs.account || '').toLowerCase();
  const startDate = attrs.start_date || '';
  if (startDate.startsWith(dayStr) && account.includes(leadName)) {
    const recs = demo.relationships?.recordings?.data || [];
    if (recs.length > 0 && recordingMap[recs[0].id]) {
      matchedToken = recordingMap[recs[0].id];
      break;
    }
  }
}

if (!matchedToken) {
  return [{ json: { transcript: null, note: null, count: 0 } }];
}

let transcriptText;
try {
  transcriptText = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://demodesk.com/api/v1/recordings/' + matchedToken + '/transcript',
    headers: {
      'api-key': $env.DEMODESK_API_KEY,
      'Accept': 'text/plain'
    }
  });
  if (typeof transcriptText !== 'string') transcriptText = JSON.stringify(transcriptText);
} catch (e) {
  return [{ json: { transcript: null, note: null, count: 0 } }];
}

const aiResult = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.openai.com/v1/chat/completions',
  headers: {
    'Authorization': 'Bearer ' + $env.OPENAI_API_KEY,
    'Content-Type': 'application/json'
  },
  body: JSON.stringify({
    model: 'gpt-4o',
    messages: [
      { role: 'system', content: 'Fasse das folgende Gespraechstranskript kurz und strukturiert zusammen. Gib die wichtigsten Punkte, Ergebnisse und naechste Schritte an. Antworte auf Deutsch.' },
      { role: 'user', content: transcriptText }
    ]
  })
});

const aiParsed = typeof aiResult === 'string' ? JSON.parse(aiResult) : aiResult;
const summary = aiParsed.choices?.[0]?.message?.content || '';

function uuid() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
  });
}

const transcript = {
  source_type: 'demodesk',
  source_id: uuid(),
  content: transcriptText,
  call_type: 'strategiegespraech',
  summary: summary,
  url: matchedToken,
  synced_at: new Date().toISOString()
};

const note = {
  lead_id: leadId,
  note: 'Strategiegespraech - Zusammenfassung\n\n' + summary + '\n\n---\nDatum: ' + dateCreated
};

return [{ json: { transcript, note, count: 1 } }];
